function openRecordDialog(type){
 recordType.value=type;recordDialogTitle.textContent="Add "+type[0].toUpperCase()+type.slice(1)+" Record";
 recordFields.innerHTML=`<div class="form-grid">${schemas[type].map(([n,l,t,o])=>{if(t==="textarea")return `<label style="grid-column:1/-1">${l}<textarea name="${n}"></textarea></label>`;if(t==="select")return `<label>${l}<select name="${n}">${o.split("|").map(x=>`<option>${x}</option>`).join("")}</select></label>`;return `<label>${l}<input name="${n}" type="${t}" ${t==="number"?'min="0" max="100"':''}></label>`}).join("")}</div>`;
 recordDialog.showModal();
 setTimeout(()=>{applyCapturedLocation();if(state.fieldVoiceNote){const ta=recordFields.querySelector("textarea");if(ta&&!ta.value)ta.value=state.fieldVoiceNote;state.fieldVoiceNote="";}},0);
}
recordForm.addEventListener("submit",async e=>{
 e.preventDefault();const i=getInquiry();if(!i)return;const type=recordType.value,fd=new FormData(e.target),r={id:uid(),createdAt:now()};
 for(const [k,v] of fd.entries()){if(k==="file"&&v instanceof File&&v.size){r.dataUrl=await fileToDataUrl(v)}else if(k!=="file")r[k]=v}
 if(type==="friction"){const base=(Number(r.frequency)||0)*(Number(r.severity)||0)*(Number(r.reach)||0)*(Number(r.confidence)||0)/100;r.priority=Math.round(base/Math.max(1,Number(r.effort)||1))}
 if(type==="change"&&compareSelection.length===2){r.observationA=compareSelection[0];r.observationB=compareSelection[1]}
 const key={observe:"observations",evidence:"evidence",station:"stations",change:"changes",friction:"frictions",cause:"rootCauses",intervention:"interventions",interventionEvent:"interventionEvents",action:"actions",stakeholder:"stakeholders",guide:"interviewGuides",theme:"themes",listen:"perspectives",predict:"forecasts",assumption:"assumptions",experiment:"experiments",inference:"inferences",hypothesis:"hypotheses",relationship:"relationships",lesson:"lessons",review:"reviews"}[type];
 i[key].push(r);i.updatedAt=now();saveState();recordDialog.close();e.target.reset();renderInquiry();
});
function fileToDataUrl(file){return new Promise((resolve,reject)=>{const reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.onerror=reject;reader.readAsDataURL(file)})}
function deleteRecord(type,id){const i=getInquiry(),key={observe:"observations",evidence:"evidence",station:"stations",change:"changes",friction:"frictions",cause:"rootCauses",intervention:"interventions",interventionEvent:"interventionEvents",action:"actions",stakeholder:"stakeholders",guide:"interviewGuides",theme:"themes",listen:"perspectives",predict:"forecasts",assumption:"assumptions",experiment:"experiments",inference:"inferences",hypothesis:"hypotheses",relationship:"relationships",lesson:"lessons",review:"reviews"}[type];i[key]=i[key].filter(x=>x.id!==id);saveState();renderInquiry()}
function toggleArchive(id){const i=state.inquiries.find(x=>x.id===id);i.archived=!i.archived;saveState();currentView=i.archived?"archive":"inquiries";render()}
function fieldCapture(){const id=fieldInquiry.value;if(!id)return;currentInquiryId=id;currentView="inquiry";currentTab="observe";render();openRecordDialog("observe")}
function fieldEvidence(){const id=fieldInquiry.value;if(!id)return;currentInquiryId=id;currentView="inquiry";currentTab="evidence";render();openRecordDialog("evidence")}
function visitStation(iid,sid){currentInquiryId=iid;currentView="inquiry";currentTab="observe";render();openRecordDialog("observe");setTimeout(()=>{const x=recordFields.querySelector('[name="stationId"]');if(x)x.value=sid},0)}
function fieldQuick(type){const id=fieldInquiry.value;if(!id)return;currentInquiryId=id;currentView="inquiry";currentTab=type==='listen'?'listen':type==='friction'?'diagnose':type==='action'?'actions':type==='change'?'changes':'observe';render();openRecordDialog(type);setTimeout(applyCapturedLocation,0)}
function captureLocation(){if(!navigator.geolocation)return alert('Geolocation is not available in this browser.');fieldLocation.textContent='Capturing location…';navigator.geolocation.getCurrentPosition(p=>{state.fieldLocation={latitude:p.coords.latitude.toFixed(6),longitude:p.coords.longitude.toFixed(6),accuracy:Math.round(p.coords.accuracy),capturedAt:now()};saveState();fieldLocation.textContent=`${state.fieldLocation.latitude}, ${state.fieldLocation.longitude} · accuracy ±${state.fieldLocation.accuracy} m`;},e=>fieldLocation.textContent='Location unavailable: '+e.message,{enableHighAccuracy:true,timeout:10000})}
function applyCapturedLocation(){const loc=state.fieldLocation;if(!loc||!window.recordFields)return;const location=recordFields.querySelector('[name="location"]');if(location&&!location.value)location.value=`${loc.latitude}, ${loc.longitude}`;const lat=recordFields.querySelector('[name="latitude"]'),lon=recordFields.querySelector('[name="longitude"]');if(lat)lat.value=loc.latitude;if(lon)lon.value=loc.longitude}
function startVoiceNote(){const SR=window.SpeechRecognition||window.webkitSpeechRecognition;if(!SR)return alert('Voice transcription is not supported by this browser.');const r=new SR();r.lang='en-US';r.interimResults=false;r.onresult=e=>{state.fieldVoiceNote=e.results[0][0].transcript;alert('Voice note captured. It will be inserted into the next open record form.');};r.onerror=e=>alert('Voice capture failed: '+e.error);r.start()}
function openMap(lat,lon){window.open(`https://www.openstreetmap.org/?mlat=${encodeURIComponent(lat)}&mlon=${encodeURIComponent(lon)}#map=18/${encodeURIComponent(lat)}/${encodeURIComponent(lon)}`,'_blank')}
function printStationCard(iid,sid){const i=state.inquiries.find(x=>x.id===iid),s=i&&(i.stations||[]).find(x=>x.id===sid);if(!s)return;const w=window.open('','_blank');w.document.write(`<title>${esc(s.name)} Station Card</title><style>body{font-family:system-ui;padding:32px;max-width:700px;margin:auto}h1{font-size:28px}.code{font-family:monospace;border:2px solid;padding:14px;font-size:18px}.box{border:1px solid #bbb;padding:14px;margin:12px 0}</style><h1>${esc(s.name)}</h1><p>${esc(i.title)}</p><div class="code">DRIFT-STATION:${esc(s.id)}</div><div class="box"><strong>Location</strong><p>${esc(s.location||'')}</p><strong>Photo angle</strong><p>${esc(s.photoAngle||'')}</p></div><div class="box"><strong>Prompts</strong><p>${esc(s.prompts||'')}</p><strong>Required measurements</strong><p>${esc(s.measurements||'')}</p><strong>Checklist</strong><p>${esc(s.checklist||'')}</p></div>`);w.document.close();w.print()}
function clearAllData(){if(confirm("Delete all Drift data stored in this browser?")){state=blankState();saveState();render()}}

