document.querySelectorAll(".nav button").forEach(b=>b.onclick=()=>{currentView=b.dataset.view;render()});
document.querySelectorAll("[data-close]").forEach(b=>b.onclick=()=>document.getElementById(b.dataset.close).close());
newInquiryBtn.onclick=openInquiryDialog;loadDemoBtn.onclick=loadDemo;
themeBtn.onclick=()=>{state.theme=state.theme==="dark"?"light":"dark";setTheme();saveState()};
quickCaptureBtn.onclick=()=>{const first=activeInquiries()[0];if(!first){openInquiryDialog();return}currentInquiryId=first.id;currentView="inquiry";currentTab="observe";render();openRecordDialog("observe")};
exportBtn.onclick=()=>{const blob=new Blob([JSON.stringify(state,null,2)],{type:"application/json"}),a=document.createElement("a");a.href=URL.createObjectURL(blob);a.download=`drift-v5-foundation-backup-${new Date().toISOString().slice(0,10)}.json`;a.click();URL.revokeObjectURL(a.href)};
importBtn.onclick=()=>importFile.click();
importFile.onchange=async e=>{try{const data=JSON.parse(await e.target.files[0].text());state={...blankState(),...data};saveState();setTheme();render();alert("Import complete.")}catch(err){alert("Could not import this file: "+err.message)}finally{e.target.value=""}};
